                Secure = Request.IsHttps, // secure in production, allow insecure in dev
                SameSite = SameSiteMode.Lax,
                Expires = refreshToken.ExpiresAt,
                Path = "/"
            };
            Response.Cookies.Append("refresh_token", refreshTokenValue, cookieOptions);

